igns"},{name:"CNS symptoms/signs"},{name:"GUT symptoms/signs"}]; return listData}, "getComorbidillness" : function(){ var listData=[{name:"Diabetes"},{name:"Asthma"},{name:"Epilepsy"},{name:"Hypothyroid"},{name:"Hypertension"},{name:"IHD"},{name:"RHD"},{name:"Hyperthyroid"},{name:"Other"}]; return listData}, "getGeneralPhysicalExamination" : function(){ var listData=[{name:"Peripheral Pulses"},{name:"Clubbing"},{name:"Pallor"},{name:"Lymphadenopathy"},{name:"Pedal edema"},{name:"Icterus"}]; return listData}}$tdata$, 0, 1, NOW(), NOW());
