{name:"Splenomegaly"},{name:"Ascites"}]; return listData},"getProstate" : function(){ var listData=[{name:"Normal"},{name:"Tender"},
{name:"Nodule"},{name:"Prostatomegaly"}]; return listData},"getConsistency" : function(){ var listData=[{name:"Normal"},{name:"Firm"},
{name:"Hard"},{name:"Boggy"},{name:"Clinically Benign"},{name:"Suspicious"},{name:"Malignant"},
{name:"Rectual Lumen Infiltration"}]; return listData;},"getUrinaryMaster" : function(){ var urinaryMaster=[{name:"Frequency "},
{name:"Hesitancy"},{name:"Nocturia"},{name:"Intermittency"},{name:"Urgency"},{name:"Sensation Of Incomplete Evacuation"},
{name:"Urge Incontinence"}]; return urinaryMaster;},"getInflammationMaster" : function(){ var inflammationMaster = [{name: "ABD Pain"}, 
{name: "Vomiting"},{name: "Burning Micturition"}, {name: "Strangury"},{name: "Dysuria"},{name: "Pyuria"},{name: "Hematuria"},{name: "H/O Contact"}, 
{name: "Fever"},{name: "Urethral Discharge"}]; return inflammationMaster;},"getHaematuriaMaster" : function(){ var haematuriaMaster= [{name: "Painless"},
{name: "Painful"},{name: "Gross"}, {name: "Microscopic"},{name: "Total"},{name: "Initial"},{name: "Terminal"},{name: "Clots"}, 
{name: "Noclots"}]; return haematuriaMaster;},"getRetentionMaster" : function(){ var retentionMaster= [{name: "Acute Retention"}, 
{name: "Dribbling"},{name: "Chronic Retention"}, {name: "Post Void Dribbling"}]; return retentionMaster;},
"getIncontinenceMaster" : function(){ var incontinenceMaster= [{name: "Stress"}, {name: "Mixed"},{name: "Urge"}, 
{name: "Overflow"},{name: "Total"},{name: "Nocturnal Enuresis"}]; return incontinenceMaster;},
"getTestesMaster" : function(){ var testesMaster= [{name: "Pain"}, {name: "Undescended"},
{name: "Swelling"},{name: "Mixed"},{name: "Trauma"}, {name: "Fever"}]; return testesMaster;},
"getPenisMaster" : function(){ var penisMaster= [{name: "Inability To Retract Prepuce"}, 
{name: "Constriction Prepuce"},{name: "Penile Curvature"},{name: "Nodule"},{name: "Glans Lesion"}, 
{name: "Painful Ejaculation"},{name: "Bloody Ejaculate"}]; return penisMaster;},
"getRenalFailureMaster" : function(){ var renalFailureMaster= [{name: "Edema"}, {name: "Vomiting"},
{name: "Hiccoughs"},{name: "Nausea"},{name: "Anorexia"}, {name: "Dyspnoea"}]; return renalFailureMaster;},
"getRightKidney" : function(){ var rightKidneyMaster= [{name: "Normal"}, {name: "Tender"},
{name: "Palpable"},{name: "Mass"},{name: "Bruit"}]; return rightKidneyMaster;},
"getLeftKidney" : function(){ var leftKidneyMaster= [{name: "Normal"}, {name: "Tender"},
{name: "Palpable"},{name: "Mass"},{name: "Bruit"}]; return leftKidneyMaster;}}$tdata$, 0, 1, NOW(), NOW());
INSERT INTO template (templatename, template, templatedata, templatetype, status, created_at, modified_at)
VALUES ('ONCOLOGY', $tmpl$div(class='col-lg-7 col-xs-8')
  h4(class='heading1', ng-if='tMode=="edit" || (tMode!="edit"  && (tForm.vitalsigns.temperature || tForm.vitalsigns.pulseRate || tForm.vitalsigns.BPHigh || tForm.vitalsigns.BPLow || tForm.vitalsigns.height))') VitalSigns
  div(class='row form-group')
    div(ng-if="validatePermission('tForm.vitalsigns.temperature')")
      label(class='col-lg-2 col-xs-2 control-label',ng-if="tMode!='print'") Temperature
      img(class='col-lg-2 col-xs-2',ng-if="tMode=='print'",style="height: 30px;float: left;",src="assets/images/temperature.png")
      div(class='col-lg-2 col-xs-2',style='padding:0px;')
        textbox(ng-model='tForm.vitalsigns.temperature',style='width:65%;float:left')
        span(style='padding-top: 2px;float: left;width: 35%;text-align: right;') F/C
    div(ng-if="validatePermission('tForm.vitalsigns.pulseRate')")
      label(class='col-lg-2 col-xs-2 control-label',ng-if="tMode!='print'") Pulse Rate
      img(class='col-lg-2 col-xs-2',ng-if="tMode=='print'",style="height: 30px;float: left;",src="assets/images/pulse.png")
      div(class='col-lg-2 col-xs-2',style='padding:0px;')
        textbox(ng-model='tForm.vitalsigns.pulseRate',style='width:65%;float:left')
        span(style='padding-top: 2px;float: left;width: 35%;text-align: right;') bpm
    div(ng-if="validatePermission('tForm.vitalsigns.BPHigh') || validatePermission('tForm.vitalsigns.BPLow')")
      label(class='col-lg-1 col-xs-1 control-label',ng-if="tMode!='print'") BP
      img(class='col-lg-2 col-xs-2',ng-if="tMode=='print'",style="height: 30px;float: left;",src="assets/images/bp.png")
      div(class='col-lg-3 col-xs-2',style='padding:0px;')
        textbox(ng-model='tForm.vitalsigns.BPHigh',style='width:32%;float:left')
        span(style='padding-top: 2px;float: left;font-size:25px') /
        textbox(ng-model='tForm.vitalsigns.BPLow',style='width:32%;float:left')
        span(style='padding-top: 2px;float: left;width: 28%;text-align: right;') mmHg
  div(class='row form-group',style='margin-top: 25px;')
    div(ng-if="validatePermission('tForm.vitalsigns.height')")
      label(class='col-lg-2 col-xs-2 control-label',ng-if="tMode!='print'") Height
      img(class='col-lg-2 col-xs-2',ng-if="tMode=='print'",style="height: 30px;float: left;",src="assets/images/height.png")
      div(class='col-lg-2 col-xs-2',style='padding:0px;')
        textbox(ng-model='tForm.vitalsigns.height',style='width:65%;float:left',ng-change='func.calculateBMI(tForm.vitalsigns.weight,tForm.vitalsigns.height)')
        span(style='padding-top: 2px;float: left;width: 35%;text-align: right;') cm
    div(ng-if="validatePermission('tForm.vitalsigns.weight')")
      label(class='col-lg-2 col-xs-2 control-label',ng-if="tMode!='print'") Weight
      img(class='col-lg-2 col-xs-2',ng-if="tMode=='print'",style="height: 30px;float: left;",src="assets/images/weight.png")
      div(class='col-lg-2 col-xs-2',style='padding:0px;')
        textbox(ng-model='tForm.vitalsigns.weight',style='width:65%;float:left',ng-change='func.calculateBMI(tForm.vitalsigns.weight,tForm.vitalsigns.height)')
        span(style='padding-top: 2px;float: left;width: 35%;text-align: right;') kg
    div(ng-if='bmiResult && tForm.vitalsigns.weight && tForm.vitalsigns.height')
      label(class='col-lg-1 col-xs-2 control-label')  BMI
      div(class='col-lg-1 col-xs-2 control-label')
        strong(ng-bind="bmiResult")

  div(class='row form-group',style='margin-top: 25px;')
    div(ng-if="validatePermission('tForm.vitalsigns.ecog')")
      label(class='col-lg-2 col-xs-2 control-label') ECOG
      div(class='col-lg-2 col-xs-2',style='padding:0px;')
        textbox(ng-model='tForm.vitalsigns.ecog',style='width:72%;float:left')

    div(ng-if="validatePermission('tForm.vitalsigns.bsa')")
      label(class='col-lg-2 col-xs-2 control-label') BSA
      div(class='col-lg-2 col-xs-2',style='padding:0px;')
        textbox(ng-model='tForm.vitalsigns.bsa',style='width:65%;float:left')
        span(style='padding-top: 2px;float: left;width: 35%;text-align: right;') m 
          sup 2

div(class='col-lg-5 col-xs-4')
  h4(class='heading1', ng-if='tMode=="edit" || tForm.vitalsigns.painScore') Pain Score
  div(ng-if='tMode=="print"') {{tForm.vitalsigns.painScore}}
  div(class='form-group painscore',style='padding: 0px 35px;')
    slider(value-max='10', step='1',t-mode='tMode', ng-model='tForm.vitalsigns.painScore')

  
div(class='col-lg-6 col-xs-6')
  div(ng-if='validatePermission("tForm.patientComplaint")')
    h4(class='heading1') Patient Complaint
    div(class='form-group')
        div(class='col-lg-offset-1 col-lg-11 col-xs-offset-1 col-xs-11')
            textbox(ng-model='tForm.patientComplaint' , rows='3')
  div(ng-if='validatePermission("tForm.onExamination")')
    h4(class='heading1') On Examination
    div(class='form-group')
        div(class='col-lg-offset-1 col-lg-11 col-xs-offset-1 col-xs-11')
            textbox(ng-model='tForm.onExamination' , rows='4')
  div(ng-if='validatePermission("tForm.labTests")')
    h4(class='heading1', ng-if='tMode=="edit" || (tMode!="edit"  && (tForm.labTests.WBC || tForm.labTests.Hb || tForm.labTests.Htc || tForm.labTests.na || tForm.labTests.Platelet || tForm.labTests.na || tForm.labTests.cl || tForm.labTests.ca || tForm.labTests.k || tForm.labTests.hco || tForm.labTests.mg))') Laboratory
    div(class='row form-group')
      div(ng-if="validatePermission('tForm.labTests.WBC')")
        label(class='col-lg-2 col-xs-2 control-label') WBC
        div(class='col-lg-2 col-xs-2',style='padding:0px;')
          textbox(ng-model='tForm.labTests.WBC',style='width:72%;float:left')        
      div(ng-if="validatePermission('tForm.labTests.Hb')")
        label(class='col-lg-2 col-xs-2 control-label') Hb
        div(class='col-lg-2 col-xs-2',style='padding:0px;')
          textbox(ng-model='tForm.labTests.Hb',style='width:72%;float:left')
      div(ng-if="validatePermission('tForm.labTests.Htc')")
        label(class='col-lg-2 col-xs-2 control-label') Htc
        div(class='col-lg-2 col-xs-2',style='padding:0px;')
          textbox(ng-model='tForm.labTests.Htc',style='width:72%;float:left')
    div(class='row form-group',style='margin-top: 25px;')
      div(ng-if="validatePermission('tForm.labTests.Platelet')")
        label(class='col-lg-2 col-xs-2 control-label') Platelet
        div(class='col-lg-2 col-xs-2',style='padding:0px;')
          textbox(ng-model='tForm.labTests.Platelet',style='width:72%;float:left')
      div(ng-if="validatePermission('tForm.labTests.na')")
        label(class='col-lg-2 col-xs-2 control-label') Na
          sup +
        div(class='col-lg-2 col-xs-2',style='padding:0px;')
          textbox(ng-model='tForm.labTests.na',style='width:72%;float:left')
      div(ng-if="validatePermission('tForm.labTests.cl')")
        label(class='col-lg-2 col-xs-2 control-label') Cl
          sup -
        div(class='col-lg-2 col-xs-2',style='padding:0px;')
          textbox(ng-model='tForm.labTests.cl',style='width:72%;float:left')
    div(class='row form-group',style='margin-top: 25px;')
      div(ng-if="validatePermission('tForm.labTests.ca')")
        label(class='col-lg-2 col-xs-2 control-label') Ca
          sup 2+
        div(class='col-lg-2 col-xs-2',style='padding:0px;')
          textbox(ng-model='tForm.labTests.ca',style='width:72%;float:left')
      div(ng-if="validatePermission('tForm.labTests.k')")
        label(class='col-lg-2 col-xs-2 control-label') K
          sup +
        div(class='col-lg-2 col-xs-2',style='padding:0px;')
          textbox(ng-model='tForm.labTests.k',style='width:72%;float:left')
      div(ng-if="validatePermission('tForm.labTests.hco')")
        label(class='col-lg-2 col-xs-2 control-label') HCO
          sub 3-
        div(class='col-lg-2 col-xs-2',style='padding:0px;')
          textbox(ng-model='tForm.labTests.hco',style='width:72%;float:left')
    div(class='row form-group',style='margin-top: 25px;')
      div(ng-if="validatePermission('tForm.labTests.mg')")
        label(class='col-lg-2 col-xs-2 control-label') Mg
          sup 2+
        div(class='col-lg-2 col-xs-2',style='padding:0px;')
          textbox(ng-model='tForm.labTests.mg',style='width:72%;float:left')

div(class='col-lg-5 col-xs-5')
  h4(class='heading1', ng-if='tMode=="edit" && tForm.fullBodyChart.length') Brief History
  div(class='form-group')
    imageedit(style='height:480px;',class='col-lg-12 col-xs-10', srct='assets/images/full_body.png',ng-model='tForm.fullBodyChart', ng-if='tMode=="edit" || tForm.fullBodyChart'))

div(class='col-lg-10 col-xs-10')
  div(ng-if='validatePermission("tForm.radiology")')
    h4(class='heading1') Radiology
    div(class='form-group') 
      div(class='col-lg-offset-1 col-lg-11 col-xs-offset-1 col-xs-11')
          textbox(ng-model='tForm.radiology' , rows='3')

div(class='col-lg-10 col-xs-10')
  div(ng-if='validatePermission("tForm.pathology")')
    h4(class='heading1') Pathology
    div(class='form-group')
      div(class='col-lg-offset-1 col-lg-11 col-xs-offset-1 col-xs-11')
        textbox(ng-model='tForm.pathology' , rows='3')

div(class='col-lg-10 col-xs-10')
  div(ng-if='validatePermission("tForm.diagnosis")')
    h4(class='heading1') Diagnosis /Impression
    div(class='form-group')
      div(class='col-lg-offset-1 col-lg-11 col-xs-offset-1 col-xs-11')
        textbox(ng-model='tForm.diagnosis' , rows='3')

div(class='col-lg-10 col-xs-10')
  div(ng-if='validatePermission("tForm.care")')
    h4(class='heading1') Care Plan
    div(class='form-group')
      div(class='col-lg-offset-1 col-lg-11 col-xs-offset-1 col-xs-11')
        textbox(ng-model='tForm.care' , rows='3')

div(class='col-lg-10 col-xs-10')
  div(ng-if='validatePermission("tForm.medicines")')
    h4(class='heading1') Medication
    div(class='form-group')
      div(class='col-lg-offset-1 col-lg-11 col-xs-offset-1 col-xs-11')
        textbox(ng-model='tForm.medicines' , rows='2')

div(class='col-lg-10 col-xs-10')
  div(ng-if='validatePermission("tForm.referal")')
    h4(class='heading1') Referal
    div(class='form-group')
      div(class='col-lg-offset-1 col-lg-11 col-xs-offset-1 col-xs-11')
        textbox(ng-model='tForm.referal' , rows='2')

div(class='col-lg-10 col-xs-10')
  div(ng-if='validatePermission("tForm.nextAppointment")')
    h4(class='heading1') Next Appointment
    div(class='form-group')
      div(class='col-lg-offset-1 col-lg-11 col-xs-offset-1 col-xs-11')
        textbox(ng-model='tForm.nextAppointment' , rows='2')

div(class='col-lg-10 col-xs-10')
  div(ng-if='validatePermission("tForm.diagnosisCodeText") || tForm.diagnosisCode.length > 0')
    h4(class='heading1') Diagnosis(ICD-10) 
    div(class='form-group')
      div(class='col-lg-offset-1 col-lg-11 col-xs-offset-1 col-xs-11',style="padding-left:0px;padding-right:0px;") 
        div(class='col-lg-12 col-md-12 col-sm-12 col-xs-12 form-group',ng-if='tForm.diagnosisCode.length > 0 || tMode=="edit"') 
          diagnostic-code(ng-model='tForm.diagnosisCode',t-mode='tMode')
        div(class='col-lg-12 col-md-12 col-sm-12 col-xs-12',ng-if='validatePermission("tForm.diagnosisCodeText")') 
          textbox(rows='2', ng-model='tForm.diagnosisCodeText')

div(class='col-lg-10 col-xs-10')
  div(ng-if='validatePermission("tForm.review")')
    h4(class='heading1') Follow-Up
    div(class='form-group')
      div(class='col-lg-offset-1 col-lg-11 col-xs-offset-1 col-xs-11')
        textbox(ng-model='tForm.review' , rows='2')$tmpl$, $tdata${"setLabTest": function(testName) {
    if(!scope.tForm.labTests)
      scope.tForm.labTests=[]
var index=scope.tForm.labTests.indexOf(testName);
    if(index >= 0)
      scope.tForm.labTests.splice(index,1)
    else
      scope.tForm.labTests.push(testName)  
}}$tdata$, 0, 1, NOW(), NOW());
INSERT INTO template (templatename, template, templatedata, templatetype, status, created_at, modified_at)
VALUES ('ANDROLOGY', $tmpl$div(class='row form-group')
  h4(class='heading1 col-lg-2 col-xs-2', ng-if='tMode=="edit" || tForm.andrology.status || tForm.andrology.Consummated || tForm.andrology.Unconsummated || tForm.examination.noOfchildrens', style="font-weight: bold;margin: 0 0 0 5px;") Andrology
  div(class='col-lg-9 col-xs-9')
    div(ng-if="validatePermission('tForm.andrology.status')")
      div(class='col-lg-2 col-xs-1')
        selectbox(ng-model='tForm.andrology.status', ng-values='["MARRIED","UNMARRIED","DIVORCED"]')          
    div(class="col-lg-5 col-xs-4", style="margin: -7px 0px;")    
      div(class='col-lg-6 col-xs-6' , ng-if="validatePermission('tForm.andrology.Consummated')")
        div.checkbox
          label
            input(type='checkbox', value='true', ng-model='tForm.andrology.Consummated', ng-if='tMode=="edit"')
            Option(ng-if='tForm.andrology.Consummated|| tMode=="edit"') Consummated
      div(class='col-lg-6 col-xs-6' , ng-if="validatePermission('tForm.andrology.Unconsummated')")
        div.checkbox
          label
            input(type='checkbox', value='false', ng-model='tForm.andrology.Unconsummated', ng-if='tMode=="edit"')
            Option(ng-if='tForm.andrology.Unconsummated|| tMode=="edit"') Unconsummated
    div(ng-if="validatePermission('tForm.examination.noOfchildrens')")
      label(class='col-lg-2 col-xs-3 control-label') No of Children
      div(class='col-lg-2 col-xs-1')
        textbox(ng-model='tForm.examination.noOfchildrens')        

div(ng-if="validatePermission('tForm.chiefComplaints')")
  div(class='row form-group')
    h4(class='heading1 col-lg-2 col-xs-2' , style="font-weight: bold;margin: 0 0 0 5px;") Chief Complaints
    div(class='col-lg-2 col-xs-1')
      selectbox(ng-model='tForm.chiefComplaintsList', ng-values='["ED","PE","ED+PE"]') 
    div(class='col-lg-6 col-xs-8' )
      textbox(ng-model='tForm.chiefComplaints', rows='2')

div(ng-if="validatePermission('tForm.evolution')")
  div(class='row form-group')
    h4(class='heading1 col-lg-2 col-xs-2' , style="font-weight: bold;margin: 0 0 0 5px;") Duration & Evolution
    div(class='col-lg-8 col-xs-8')
      textbox(ng-model='tForm.evolution', rows='2')

div(ng-if="validatePermission('tForm.attributes')")
  div(class='row form-group')
    h4(class='heading1 col-xs-2 col-xs-2' , style="font-weight: bold;margin: 0 0 0 5px;") Attributes Problem To
    div(class='col-lg-8 col-xs-8')
      textbox(ng-model='tForm.attributes', rows='2')   

div(class='row form-group')  
  div(ng-if="validatePermission('tForm.libido')")
    h4(class='heading1 col-lg-2 col-xs-2' , style="font-weight: bold;margin: 0px 0 0 5px;") Libido
    div(class='col-lg-2 col-xs-2')
      selectbox(ng-model='tForm.libidoList', ng-values='["LOW","NORMAL"]') 
    div(class='col-lg-3 col-xs-3')
      textbox(ng-model='tForm.libido')
div(class='row form-group')
  div(ng-if="validatePermission('tForm.arousal')")
    h4(class='heading1 col-lg-2 col-xs-2' , style="font-weight: bold;margin: 0px 0 0 5px;") Arousal
    div(class='col-lg-2 col-xs-2')
      selectbox(ng-model='tForm.arousalList', ng-values='["ABSENT","PRESENT"]') 
    div(class='col-lg-3 col-xs-3')
      textbox(ng-model='tForm.arousal')

h4(class='heading1' ,ng-if='tMode=="edit" || (tForm.regidity.sexual|| tForm.regidity.morning || tForm.regidity.masturbatory || tForm.duration.sexualBox || tForm.duration.morningBox || tForm.duration.masturbatoryBox )',style='font-weight:bold') Erection
div(class='row')
  label(class='col-lg-2 col-xs-2 control-label' ,ng-if='tMode=="edit" || (tForm.regidity.sexual|| tForm.regidity.morning || tForm.regidity.masturbatory)' ,style="text-align: center;") Rigidity
  div(class='col-lg-2 col-xs-2', ng-if="validatePermission('tForm.regidity.sexual')")
    div.checkbox
      input(type='checkbox', value='true', ng-model='tForm.regidity.sexual', ng-if='tMode=="edit"')
      Option(ng-if='tForm.regidity.sexual || tMode=="edit"') Sexual
  div(class='col-lg-2 col-xs-2' , ng-if="validatePermission('tForm.regidity.morning')")
    div.checkbox
      input(type='checkbox', value='false', ng-model='tForm.regidity.morning', ng-if='tMode=="edit"')
      Option(ng-if='tForm.regidity.morning || tMode=="edit"') Morning
  div(class='col-lg-2 col-xs-2' , ng-if="validatePermission('tForm.regidity.masturbatory')")
    div.checkbox
      input(type='checkbox', value='false', ng-model='tForm.regidity.masturbatory', ng-if='tMode=="edit"')
      Option(ng-if='tForm.regidity.masturbatory || tMode=="edit"') Masturbatory

div(class='row form-group', ng-if='tMode=="edit" || tForm.duration.sexualBox || tForm.duration.morningBox || tForm.duration.masturbatoryBox')
  label(class='col-lg-2 col-xs-2 control-label', ,style="text-align: center;") Duration(Mins)
  div(ng-if="validatePermission('tForm.duration.sexualBox')")
    div(class='col-lg-2 col-xs-2')
      textbox(ng-model='tForm.duration.sexualBox')
  div(ng-if="validatePermission('tForm.duration.morningBox')")
    div(class='col-lg-2 col-xs-2')
      textbox(ng-model='tForm.duration.morningBox') 
  div(ng-if="validatePermission('tForm.duration.masturbatoryBox')")
    div(class='col-lg-2 col-xs-2')
      textbox(ng-model='tForm.duration.masturbatoryBox')
      
div(class='row form-group')  
  div(ng-if="validatePermission('tForm.penetration')")
    h4(class='heading1 col-lg-2 col-xs-2' , style="font-weight: bold;margin: 0px 0 0 5px;") Penetration
    div(class='col-lg-2 col-xs-2')
      selectbox(ng-model='tForm.penetration', ng-values='["ABSENT","PRESENT","FULL"]') 
    
div(class='row form-group')
  div(ng-if="validatePermission('tForm.orgasm')")
    h4(class='heading1 col-lg-2 col-xs-2' , style="font-weight: bold;margin: 0px 0 0 5px;") Orgasm
    div(class='col-lg-2 col-xs-2')
      selectbox(ng-model='tForm.orgasm', ng-values='["ABSENT","PRESENT"]')   
    
div(ng-if="validatePermission('tForm.ejaculation.ejaculationList || tForm.ejaculation.Ivelt')")
  div(class='row form-group') 
    h4(class='heading1 col-lg-2 col-xs-2' , style="font-weight: bold;margin: 0px 0 0 5px;") Ejaculation
    div(class='col-lg-2 col-xs-2')
      selectbox(ng-model='tForm.ejaculation.ejaculationList', ng-values='["ABSENT","PRESENT"]') 
    label(class='col-lg-2 col-xs-2 control-label', ng-if='tMode=="edit" || tForm.ejaculation.Ivelt') Ivelt(Mins)  
    div(class='col-lg-3 col-xs-3')
      textbox(ng-model='tForm.ejaculation.Ivelt')  

div(ng-if="validatePermission('tForm.treatmentTaken') && (tMode=='edit' || tForm.treatmentTaken.length)")
  div(class='row form-group')
    h4(class='heading1 col-lg-2 col-xs-2' , style="font-weight: bold;margin: 0px 0 0 5px;") Treatment Taken
    div(class='col-lg-8 col-xs-8', ng-init='multiListData=func.getTreatmentTakenList()')
      multi-select-list(id="treatmentTaken", t-mode="tMode",options="multiListData",selected-model="[]", auto-complete-status='true', ng-model="tForm.treatmentTaken",is-group='false')                    

div(ng-if="validatePermission('tForm.medicalHistory') && (tMode=='edit' || tForm.medicalHistory.length)")
  div(class='row form-group')
    h4(class='heading1 col-lg-2 col-xs-2' , style="font-weight: bold;margin: 0px 0 0 5px;") Medical History
    div(class='col-lg-8 col-xs-8', ng-init='multiListData=func.getMedicalHistoryList()')
      multi-select-list(id="complaient", t-mode="tMode",options="multiListData",selected-model="[]", auto-complete-status='true', ng-model="tForm.medicalHistory",is-group='false')
                    
div
  div(class='row form-group')
    h4(class='heading1 col-lg-2 col-xs-2',ng-if='tMode=="edit" || (tForm.martialRelationship.Normal || tForm.martialRelationship.Distressed || tForm.martialRelationship.Impending )',style='font-weight:bold;margin: 0px 0 0 5px;') Maritial Relationship  
    div(class='col-lg-8 col-xs-8')           
      div      
        div(class='row form-group')
          div(class='col-lg-2 col-xs-2' , ng-if="validatePermission('tForm.martialRelationship.Normal')")
            div.checkbox
              label
                input(type='checkbox', value='true', ng-model='tForm.martialRelationship.Normal', ng-if='tMode=="edit"')
                Option(ng-if='tForm.martialRelationship.Normal|| tMode=="edit"') Normal
          div(class='col-lg-2 col-xs-2' , ng-if="validatePermission('tForm.martialRelationship.Distressed')")
            div.checkbox
              label
                input(type='checkbox', value='false', ng-model='tForm.martialRelationship.Distressed', ng-if='tMode=="edit"')
                Option(ng-if='tForm.martialRelationship.Distressed|| tMode=="edit"') Distressed
          div(class='col-lg-2 col-xs-2' , ng-if="validatePermission('tForm.martialRelationship.Impending')")
            div.checkbox
              label
                input(type='checkbox', value='false', ng-model='tForm.martialRelationship.Impending', ng-if='tMode=="edit"')
                Option(ng-if='tForm.martialRelationship.Impending|| tMode=="edit"') Impending Divorce           
   
div(ng-if="validatePermission('tForm.treatmentGoals')")
  div(class='row form-group')
    h4(class='heading1 col-lg-2 col-xs-2' , style="font-weight: bold;margin: 0px 0 0 5px;") Treatment Goals
    div(class='col-lg-8 col-xs-8')
