  div(class='col-lg-8 col-xs-offset-1')
    div(class='col-lg-2' )
      div.checkbox
        label
          input(type='checkbox', value='true', ng-model='tForm.dialysate.oneFivetyMl', ng-if='tMode=="edit"')
          Option(ng-if='tForm.dialysate.oneFivetyMl || tMode=="edit"') 150ml/mt
    div(class='col-lg-2' )
      div.checkbox
        label
          input(type='checkbox', value='true', ng-model='tForm.dialysate.threeHundredMl', ng-if='tMode=="edit"')
          Option(ng-if='tForm.dialysate.threeHundredMl || tMode=="edit"') 300ml/mt
    div(class='col-lg-2' )
      div.checkbox
        label
          input(type='checkbox', value='true', ng-model='tForm.dialysate.fiveHundredMl', ng-if='tMode=="edit"')
          Option(ng-if='tForm.dialysate.fiveHundredMl || tMode=="edit"') 500ml/mt
    div(class='col-lg-2' )
      div.checkbox
        label
          input(type='checkbox', value='true', ng-model='tForm.dialysate.eightHundredMl', ng-if='tMode=="edit"')
          Option(ng-if='tForm.dialysate.eightHundredMl || tMode=="edit"') 800ml/mt


h4(class='heading1', ng-if='tMode=="edit" || tForm.machineTemp') Machine Temp
div(class='row form-group',ng-if="validatePermission('tForm.machineTemp')")
  div(class='col-lg-8 col-xs-offset-1')
    div(class='col-lg-2' )
      div.checkbox
        label
          input(type='checkbox', value='true', ng-model='tForm.machineTemp.thirtyFive ', ng-if='tMode=="edit"')
          Option(ng-if='tForm.machineTemp.thirtyFive || tMode=="edit"') 35c
    div(class='col-lg-2' )
      div.checkbox
        label
          input(type='checkbox', value='true', ng-model='tForm.machineTemp.thirtySix', ng-if='tMode=="edit"')
          Option(ng-if='tForm.machineTemp.thirtySix || tMode=="edit"') 36c
    div(class='col-lg-2' )
      div.checkbox
        label
          input(type='checkbox', value='true', ng-model='tForm.machineTemp.thirtySixPointFive', ng-if='tMode=="edit"')
          Option(ng-if='tForm.machineTemp.thirtySixPointFive || tMode=="edit"') 36.5c
    div(class='col-lg-2' )
      div.checkbox
        label
          input(type='checkbox', value='true', ng-model='tForm.machineTemp.thirtySeven', ng-if='tMode=="edit"')
          Option(ng-if='tForm.machineTemp.thirtySeven || tMode=="edit"') 37c

div(ng-if="validatePermission('tForm.firstHdpProtocol')")
  h4(class='heading1') Ist HD protocol
  div(class='form-group', ng-if="validatePermission('tForm.firstHdpProtocol')")
