      div(class='col-lg-9', ng-style='#{radioStyle}')
        radio-btn(ng-model='tForm.firstHdpProtocol', ng-data-value="{'no':'No','yes':'Yes'}")

div(ng-if="validatePermission('tForm.equipmentPreparation')")
