    div(class='col-lg-2 col-xs-offset-2' )
      div.checkbox
        label
          input(type='checkbox', value='true', ng-model='tForm.equipmentPreparation.dialyserAndReuseLableChecked', ng-if='tMode=="edit"')
          Option(ng-if='tForm.equipmentPreparation.dialyserAndReuseLableChecked || tMode=="edit"') Dialyser/Reuse Lable Checked
  div(class='row form-group',ng-if='tForm.equipmentPreparation.primingDone || tMode=="edit"')
    div(class='col-lg-2 col-xs-offset-2' )
      div.checkbox
        label
          input(type='checkbox', value='true', ng-model='tForm.equipmentPreparation.primingDone', ng-if='tMode=="edit"')
          Option(ng-if='tForm.equipmentPreparation.primingDone || tMode=="edit"') Priming Done
  div(class='row form-group',ng-if='tForm.equipmentPreparation.selfTestCompleted|| tMode=="edit"')
    div(class='col-lg-2 col-xs-offset-2' )
      div.checkbox
        label
          input(type='checkbox', value='true', ng-model='tForm.equipmentPreparation.selfTestCompleted', ng-if='tMode=="edit"')
          Option(ng-if='tForm.equipmentPreparation.selfTestCompleted || tMode=="edit"') Self Test Completed
  div(class='row form-group',ng-if='tForm.equipmentPreparation.disinfection || tMode=="edit"')
    div(class='col-lg-2 col-xs-offset-2' )
      div.checkbox
        label
          input(type='checkbox', value='true', ng-model='tForm.equipmentPreparation.disinfection', ng-if='tMode=="edit"')
          Option(ng-if='tForm.equipmentPreparation.disinfection || tMode=="edit"') Disinfection: Rinse / Decalcificant / Others
  div(class='row form-group',ng-if='tForm.equipmentPreparation.residualBloodLine || tMode=="edit"')
    div(class='col-lg-2 col-xs-offset-2' )
      div.checkbox
        label
          input(type='checkbox', value='true', ng-model='tForm.equipmentPreparation.residualBloodLine', ng-if='tMode=="edit"')
          Option(ng-if='tForm.equipmentPreparation.residualBloodLine || tMode=="edit"') Residual Blood line :Renalin Negative


div(ng-if="validatePermission('tForm.patientAssessment')")
  h4(class='heading1', ng-if='tMode=="edit" || tForm.patientAssessment') Patient Assessment
  div(class='row form-group')
    div(class='col-lg-12' )
      div(class='col-lg-3' )
        h4(class='heading1', ng-if='tMode=="edit" || tForm.patientAssessment.edema') Edema
      div(class='row')
        div(class='col-lg-8')
          div(class='col-lg-2' )
            div.checkbox
              label
                input(type='checkbox', value='true', ng-model='tForm.patientAssessment.edema.yes', ng-if='tMode=="edit"')
                Option(ng-if='tForm.patientAssessment.edema.yes || tMode=="edit"') Yes
          div(class='col-lg-2' )
            div.checkbox
              label
                input(type='checkbox', value='true', ng-model='tForm.patientAssessment.crepitation.no', ng-if='tMode=="edit"')
                Option(ng-if='tForm.patientAssessment.crepitation.no || tMode=="edit"') No
           
      div(class='col-lg-3' )
        h4(class='heading1', ng-if='tMode=="edit" || tForm.patientAssessment.recentSurgeryAndInjuryAndBleeding') Recent Surgery / Injury /Bleeding
      div(class='row')
        div(class='col-lg-8')
          div(class='col-lg-2' )
            div.checkbox
              label
                input(type='checkbox', value='true', ng-model='tForm.patientAssessment.recentSurgeryAndInjuryAndBleeding.yes', ng-if='tMode=="edit"')
                Option(ng-if='tForm.patientAssessment.recentSurgeryAndInjuryAndBleeding.yes || tMode=="edit"') Yes
          div(class='col-lg-2' )
            div.checkbox
              label
                input(type='checkbox', value='true', ng-model='tForm.patientAssessment.recentSurgeryAndInjuryAndBleeding.no', ng-if='tMode=="edit"')
                Option(ng-if='tForm.patientAssessment.recentSurgeryAndInjuryAndBleeding.no || tMode=="edit"') No
            
              
      div(class='col-lg-3' )
        h4(class='heading1', ng-if='tMode=="edit" || tForm.patientAssessment.onAnticoagulation') On Anticoagulation
      div(class='row')
        div(class='col-lg-8')
          div(class='col-lg-2' )
            div.checkbox
              label
                input(type='checkbox', value='true', ng-model='tForm.patientAssessment.onAnticoagulation.yes', ng-if='tMode=="edit"')
                Option(ng-if='tForm.patientAssessment.onAnticoagulation.yes || tMode=="edit"') Yes
          div(class='col-lg-2' )
            div.checkbox
              label
                input(type='checkbox', value='true', ng-model='tForm.patientAssessment.onAnticoagulation.no', ng-if='tMode=="edit"')
                Option(ng-if='tForm.patientAssessment.onAnticoagulation.no || tMode=="edit"') No
          
      div(class='col-lg-3' )
        h4(class='heading1', ng-if='tMode=="edit" || tForm.patientAssessment.breakAndLunchAndDinner') Break / Lunch / Dinner
      div(class='row')
        div(class='col-lg-8')
          div(class='col-lg-2' )
            div.checkbox
              label
                input(type='checkbox', value='true', ng-model='tForm.patientAssessment.breakAndLunchAndDinner.yes', ng-if='tMode=="edit"')
                Option(ng-if='tForm.patientAssessment.breakAndLunchAndDinner.yes || tMode=="edit"') Yes
          div(class='col-lg-2' )
            div.checkbox
              label
                input(type='checkbox', value='true', ng-model='tForm.patientAssessment.breakAndLunchAndDinner.no', ng-if='tMode=="edit"')
                Option(ng-if='tForm.patientAssessment.breakAndLunchAndDinner.no || tMode=="edit"') No
           
      div(class='col-lg-3' )
        h4(class='heading1', ng-if='tMode=="edit" || tForm.patientAssessment.targetWeight') Target Weight 
      div(class='row')
        div(class='col-lg-4')
          div(class='col-lg-6 col-md-1 col-sm-1 col-xs-1')
            textbox(ng-model='tForm.patientAssessment.targetWeight')


